import{_ as r,o as a,c as o,ag as e,ah as s}from"./chunks/framework.D9bIGSBm.js";const u=JSON.parse('{"title":"浏览器标签页","description":"","frontmatter":{},"headers":[],"relativePath":"features/browser.md","filePath":"features/browser.md"}'),l={name:"features/browser.md"};function n(i,t,d,h,c,p){return a(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="浏览器标签页" tabindex="-1">浏览器标签页 <a class="header-anchor" href="#浏览器标签页" aria-label="Permalink to &quot;浏览器标签页&quot;">​</a></h1><p>LoongCode 在右侧面板中内置了一个完整的浏览器，让你无需离开 IDE 就能查阅文档、测试网页，还可以将网页元素直接提供给 AI 使用。</p><blockquote><p>相关：<a href="/docs/guide/interface-overview.html">界面导览</a>、<a href="/docs/features/conversation.html">对话面板</a></p></blockquote><hr><h2 id="什么是内嵌浏览器" tabindex="-1">什么是内嵌浏览器 <a class="header-anchor" href="#什么是内嵌浏览器" aria-label="Permalink to &quot;什么是内嵌浏览器&quot;">​</a></h2><p>内嵌浏览器是右侧面板的第三种标签页类型（与文件标签、审查标签并列）。它采用系统原生浏览器内核（Windows 上为 WebView2），支持访问任意真实站点，表现与普通桌面浏览器一致。</p><p><strong>适用场景举例：</strong></p><ul><li>查阅 API 文档时，同时在左侧让 AI 写代码</li><li>把某个网页上的报错信息或 UI 元素截图提供给 AI 分析</li><li>在不切换窗口的情况下浏览 GitHub Issues 或 StackOverflow 解答</li></ul><hr><h2 id="打开浏览器标签页" tabindex="-1">打开浏览器标签页 <a class="header-anchor" href="#打开浏览器标签页" aria-label="Permalink to &quot;打开浏览器标签页&quot;">​</a></h2><ol><li>点击右侧面板顶部标签栏最右边的 <strong>+</strong> 按钮，弹出下拉菜单。</li><li>菜单中选择<strong>浏览器</strong>（另两个选项为「打开文件 Ctrl+P」和「审查」）。</li><li>右侧面板切换为浏览器视图，地址栏提示「输入网址后回车」。</li><li>在地址栏输入目标网址后按 <strong>Enter</strong> 即可加载页面。</li></ol><p><img src="'+s+'" alt="截图：右侧面板显示浏览器标签页，地址栏已输入 URL，页面正在加载，顶部工具栏显示后退/前进/停止/选元素等按钮"></p><div class="tip custom-block"><p class="custom-block-title">无协议自动补全</p><p>输入时可以省略 <code>https://</code>，LoongCode 会自动补充。如果输入内容不像网址（含空格或没有点），会自动以百度搜索兜底。</p></div><hr><h2 id="浏览器工具栏" tabindex="-1">浏览器工具栏 <a class="header-anchor" href="#浏览器工具栏" aria-label="Permalink to &quot;浏览器工具栏&quot;">​</a></h2><p>工具栏从左到右依次为：</p><table tabindex="0"><thead><tr><th>按钮（界面原文）</th><th>说明</th></tr></thead><tbody><tr><td><strong>后退</strong></td><td>返回上一页（当无历史时显示为禁用状态）</td></tr><tr><td><strong>前进</strong></td><td>前进到下一页（当无历史时显示为禁用状态）</td></tr><tr><td><strong>停止加载</strong> / 刷新</td><td>加载中点此停止；加载完成后变为刷新按钮</td></tr><tr><td><strong>地址栏</strong></td><td>显示当前 URL，可直接编辑后回车导航</td></tr><tr><td><strong>选中元素加入聊天</strong></td><td>进入「选元素模式」，点击页面元素后将其插入当前对话输入框</td></tr><tr><td><strong>打开调试工具</strong></td><td>打开独立的原生开发者工具（DevTools）窗口</td></tr><tr><td><strong>关闭浏览器</strong></td><td>关闭此浏览器标签页</td></tr></tbody></table><hr><h2 id="选取网页元素加入聊天" tabindex="-1">选取网页元素加入聊天 <a class="header-anchor" href="#选取网页元素加入聊天" aria-label="Permalink to &quot;选取网页元素加入聊天&quot;">​</a></h2><p>这是内嵌浏览器的核心功能——你可以直接点选页面上的任何元素（按钮、文字、图片区域等），将其结构化信息插入到当前对话的输入框中，再向 AI 提问。</p><p><strong>操作步骤：</strong></p><ol><li>点击工具栏中的<strong>选中元素加入聊天</strong>按钮，按钮高亮表示已进入选元素模式。</li><li>将鼠标移到页面上，目标元素会出现高亮轮廓和信息提示（标签名、颜色、字体等）。</li><li>点击想要的元素，该元素的信息（文本内容、HTML 结构、样式、位置等）会以小标签形式（类似 @ 引用文件的样式）插入当前活动任务的输入框光标处。</li><li>可以连续点击多个元素，每个元素对应一个独立的小标签。</li><li>再次点击<strong>选中元素加入聊天</strong>按钮，或按 <strong>Esc</strong> 键，退出选元素模式。</li></ol><div class="tip custom-block"><p class="custom-block-title">关闭浏览器后标签仍可发送</p><p>已选取的元素标签不依赖浏览器标签页保持打开，关闭浏览器后仍可正常发送给 AI。</p></div><hr><h2 id="ai-回复中的链接就地打开" tabindex="-1">AI 回复中的链接就地打开 <a class="header-anchor" href="#ai-回复中的链接就地打开" aria-label="Permalink to &quot;AI 回复中的链接就地打开&quot;">​</a></h2><p>对话面板中的 Markdown 链接点击后会<strong>在内嵌浏览器中就地打开</strong>，无需离开 LoongCode 切换到系统浏览器。</p><p>如果你需要在系统浏览器中打开，可以<strong>按住修饰键</strong>（Ctrl / Cmd）再点击，或使用鼠标中键点击链接。</p><hr><h2 id="多标签与切换" tabindex="-1">多标签与切换 <a class="header-anchor" href="#多标签与切换" aria-label="Permalink to &quot;多标签与切换&quot;">​</a></h2><p>右侧面板支持同时打开多个标签页（文件、审查、浏览器均可并存）。切换到其他标签页后，浏览器页面会在后台<strong>保持加载状态</strong>，切回时页面零重载，登录态和页面内容完整保留。</p><p>只有点击浏览器工具栏右侧的<strong>关闭浏览器</strong>按钮（× 图标），才会真正关闭并销毁该浏览器实例。</p><hr><h2 id="agent-使用浏览器的能力" tabindex="-1">Agent 使用浏览器的能力 <a class="header-anchor" href="#agent-使用浏览器的能力" aria-label="Permalink to &quot;Agent 使用浏览器的能力&quot;">​</a></h2><p>当你在对话中向 AI 提供了网页元素或链接，AI 可以基于这些内容进行分析、代码生成、问题排查等操作。AI 本身不会主动控制浏览器导航——浏览器的操作（地址栏输入、前进后退、选元素等）均由你手动完成后，再将内容提供给 AI。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>了解浏览器标签页后，可以前往<a href="/docs/features/usage-stats.html">使用统计</a>了解如何查看 Token 用量与使用趋势。</p>',37)])])}const b=r(l,[["render",n]]);export{u as __pageData,b as default};
